// ================================================
// CONFIGURACIÓN DE LECTORES ANVIZ EP300 PRO
// PERSONALIZAR según tu red
// ================================================
flow.set('readers', [
    { id: 'ANVIZ-01', ip: '192.168.7.243', sucursal: 'Entrada Principal', userid: 'admin', password: '12345' },
    { id: 'ANVIZ-02', ip: '192.168.7.244', sucursal: 'Salida Principal', userid: 'admin', password: '12345' },
    { id: 'ANVIZ-03', ip: '192.168.7.245', sucursal: 'Almacén',          userid: 'admin', password: '12345' },
    { id: 'ANVIZ-04', ip: '192.168.7.246', sucursal: 'Laboratorio',      userid: 'admin', password: '12345' },
    { id: 'ANVIZ-05', ip: '192.168.7.247', sucursal: 'Control',          userid: 'admin', password: '12345' }
]);

flow.set('readerIndex', 0);
flow.set('totalInsertados', 0);
flow.set('totalLectores', 0);
flow.set('totalErrores', 0);

node.log('========================================');
node.log('🔄 INICIANDO CICLO DE LECTURA ANVIZ');
node.log('========================================');

return { payload: 'start' };

const readers = flow.get('readers');
const index = flow.get('readerIndex');

if (index >= readers.length) {
    const total = flow.get('totalInsertados');
    const lectores = flow.get('totalLectores');
    const errores = flow.get('totalErrores');

    node.log('========================================');
    node.log('✅ CICLO COMPLETADO');
    node.log(`📊 Lectores OK: ${lectores}/${readers.length}`);
    node.log(`📊 Errores: ${errores}`);
    node.log(`📊 Total filas insertadas: ${total}`);
    node.log('========================================');

    flow.set('readerIndex', 0);
    flow.set('totalInsertados', 0);
    flow.set('totalLectores', 0);
    flow.set('totalErrores', 0);

    return [null, { 
        payload: 'finished', 
        totalFilas: total, 
        lectoresOk: lectores, 
        errores: errores 
    }];
}

const reader = readers[index];

node.log(`📡 [${index+1}/${readers.length}] ${reader.id} (${reader.ip}) - Login...`);

msg.readerId = reader.id;
msg.readerIp = reader.ip;
msg.sucursal = reader.sucursal;

msg.url = `http://${reader.ip}/goform/chklogin?_t=${Date.now()}`;
msg.method = 'POST';
msg.headers = {
    'Content-Type': 'application/json',
    'Accept': 'application/json, text/plain, */*',
    'Referer': `http://${reader.ip}/index.html`
};
msg.payload = {
    userid: reader.userid,
    password: reader.password
};

return [msg, null];

// =================================================
// PARSER ROBUSTO PARA JSON DE ANVIZ
// El reloj devuelve JSON con:
// 1. Trailing commas
// 2. Propiedades sin comillas en records
// =================================================

function parseAnvizJSON(text) {
    if (typeof text !== 'string') return text;

    let cleaned = text.replace(/,(\s*})/g, '$1');
    cleaned = cleaned.replace(/,(\s*\])/g, '$1');
    cleaned = cleaned.replace(/([{,]\s*)([a-zA-Z_][a-zA-Z0-9_]*)\s*:/g, '$1"$2":');

    return JSON.parse(cleaned);
}

try {
    let data = msg.payload;

    if (typeof data === 'string') {
        try {
            data = parseAnvizJSON(data);
        } catch(parseErr) {
            throw new Error(`No se puede parsear: ${parseErr.message}. Inicio: ${msg.payload.substring(0, 150)}`);
        }
    }

    if (data.code === 'error') {
        throw new Error(`Login falló: msg=${data.msg || 'sin mensaje'}`);
    }

    if (data.retvalue !== 0 && data.retvalue !== undefined) {
        throw new Error(`retvalue=${data.retvalue}: ${data.msg || 'error desconocido'}`);
    }

    const token = data.token;

    if (!token) {
        throw new Error(`No se encontró token en respuesta`);
    }

    msg.token = token;
    node.log(`✅ ${msg.readerId}: Login OK - Token JWT obtenido`);

    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const fechaHoy = `${year}-${month}-${day}`;

    msg.url = `http://${msg.readerIp}/goform/GetReportFormInfo?_t=${Date.now()}&userid=&from=${fechaHoy}&to=${fechaHoy}&intime=00:00&outtime=23:59&start=0&limit=1000`;
    msg.method = 'GET';
    msg.headers = {
        'token': token,
        'Accept': 'application/json, text/plain, */*',
        'Referer': `http://${msg.readerIp}/index.html`
    };
    msg.payload = '';

    return msg;

} catch (e) {
    node.error(`❌ ${msg.readerId}: ${e.message}`);

    const errores = flow.get('totalErrores') || 0;
    flow.set('totalErrores', errores + 1);

    msg.skipReader = true;
    msg.errorMsg = e.message;
    return msg;
}

// Parser robusto - maneja trailing commas Y propiedades sin comillas
function parseAnvizJSON(text) {
    if (typeof text !== 'string') return text;

    let cleaned = text.replace(/,(\s*})/g, '$1');
    cleaned = cleaned.replace(/,(\s*\])/g, '$1');
    cleaned = cleaned.replace(/([{,]\s*)([a-zA-Z_][a-zA-Z0-9_]*)\s*:/g, '$1"$2":');

    return JSON.parse(cleaned);
}

try {
    let data = msg.payload;

    if (typeof data === 'string') {
        data = parseAnvizJSON(data);
    }

    if (data.code === 'error' || (data.retvalue !== 0 && data.retvalue !== undefined)) {
        throw new Error(`Error API: code=${data.code}, msg=${data.msg || 'error'}`);
    }

    const records = data.record || [];

    if (!records || records.length === 0) {
        node.log(`ℹ ${msg.readerId}: sin registros`);
        const ok = flow.get('totalLectores') || 0;
        flow.set('totalLectores', ok + 1);
        return [null, msg];
    }

    const sqlRows = [];

    records.forEach(record => {
        const dni = record.id || '';
        const fecha = record.date || '';
        const firstin = record.firstin || '';
        const lastout = record.lastout || '';

        if (!dni || !fecha) return;

        if (firstin && firstin !== '') {
            sqlRows.push({
                Dni: dni,
                Fecha: fecha,
                Hora: firstin,
                Sucursal: msg.sucursal,
                HoraSeg: `${fecha} ${firstin}`,
                ipreloj: msg.readerIp
            });
        }

        if (lastout && lastout !== '') {
            sqlRows.push({
                Dni: dni,
                Fecha: fecha,
                Hora: lastout,
                Sucursal: msg.sucursal,
                HoraSeg: `${fecha} ${lastout}`,
                ipreloj: msg.readerIp
            });
        }
    });

    if (sqlRows.length === 0) {
        node.log(`ℹ ${msg.readerId}: ${records.length} registros, sin filas válidas`);
        const ok = flow.get('totalLectores') || 0;
        flow.set('totalLectores', ok + 1);
        return [null, msg];
    }

    msg.sqlRows = sqlRows;
    msg.totalRows = sqlRows.length;

    node.log(`📝 ${msg.readerId}: ${records.length} registros → ${sqlRows.length} filas`);

    return [msg, null];

} catch (e) {
    node.error(`❌ ${msg.readerId}: ${e.message}`);
    const errores = flow.get('totalErrores') || 0;
    flow.set('totalErrores', errores + 1);
    return [null, msg];
}

const rows = msg.sqlRows;

if (!rows || rows.length === 0) return null;

function escapeSql(value) {
    if (value === null || value === undefined) return '';
    return String(value).replace(/'/g, "''");
}

let sql = `INSERT INTO RelojImportacion (Dni, Fecha, Hora, Sucursal, HoraSeg, ipreloj) VALUES `;

const values = rows.map(row => {
    return `('${escapeSql(row.Dni)}', '${escapeSql(row.Fecha)}', '${escapeSql(row.Hora)}', '${escapeSql(row.Sucursal)}', '${escapeSql(row.HoraSeg)}', '${escapeSql(row.ipreloj)}')`;
}).join(', ');

sql += values + ';';

const total = flow.get('totalInsertados') + rows.length;
flow.set('totalInsertados', total);

msg.payload = sql;
msg.query = sql;
return msg;

node.log(`✅ ${msg.readerId}: ${msg.totalRows} filas insertadas`);

const ok = flow.get('totalLectores') || 0;
flow.set('totalLectores', ok + 1);

return msg;

const index = flow.get('readerIndex');
flow.set('readerIndex', index + 1);

setTimeout(() => {
    node.send({ payload: 'next' });
}, 1000);

return null;
